{
    "level": "A2",
    "intro": "W tym temacie nauczysz się poprawnie używać <strong>somewhere</strong>, <strong>anywhere</strong>, <strong>nowhere</strong> i <strong>everywhere</strong>, gdy mówimy o miejscu.",
    "rules": [
        {
            "label": "Twierdzenia",
            "color": "emerald",
            "text": "<strong>Somewhere</strong> najczęściej występuje w zdaniach twierdzących:",
            "example": "I left my phone somewhere at home."
        },
        {
            "label": "Pytania i przeczenia",
            "color": "blue",
            "text": "<strong>Anywhere</strong> zwykle pojawia się w pytaniach i przeczeniach:",
            "example": "Do you want to go anywhere tonight? / I don't want to go anywhere."
        },
        {
            "label": "Negacja i uogólnienie",
            "color": "rose",
            "text": "<strong>Nowhere</strong> oznacza „nigdzie”, a <strong>everywhere</strong> — „wszędzie”:",
            "example": "He had nowhere to sit. / There were flowers everywhere."
        }
    ]
}

{
    "title": "1. Formy i znaczenie",
    "intro": "Cztery najważniejsze słowa związane z miejscem to:",
    "items": [
        {
            "label": "Twierdzenie",
            "title": "somewhere",
            "subtitle": "gdzieś"
        },
        {
            "label": "Pytania i przeczenia",
            "title": "anywhere",
            "subtitle": "gdziekolwiek / gdzieś"
        },
        {
            "label": "Jednowyrazowa negacja",
            "title": "nowhere",
            "subtitle": "nigdzie"
        },
        {
            "label": "Uogólnienie",
            "title": "everywhere",
            "subtitle": "wszędzie"
        }
    ]
}

{
    "title": "2. Użycie w zdaniu",
    "sections": [
        {
            "label": "Twierdzenia",
            "color": "emerald",
            "description": "W zdaniach twierdzących najczęściej używamy <strong>somewhere</strong>, a przy uogólnieniu <strong>everywhere</strong>.",
            "examples": [
                {
                    "en": "He is somewhere in the building.",
                    "ua": "On jest gdzieś w budynku."
                },
                {
                    "en": "You can see flowers everywhere in spring.",
                    "ua": "Wiosną kwiaty są wszędzie."
                }
            ]
        },
        {
            "label": "Przeczenia",
            "color": "rose",
            "description": "W przeczeniach zwykle używamy <strong>anywhere</strong>. <strong>Nowhere</strong> jest pełną formą przeczącą i nie łączy się z dodatkowym <code class=\"font-mono text-xs\">not</code>.",
            "examples": [
                {
                    "en": "I don't go anywhere on Sundays.",
                    "ua": "W niedziele nigdzie nie wychodzę."
                },
                {
                    "en": "There is nowhere to park here.",
                    "ua": "Nie ma tu gdzie zaparkować."
                }
            ],
            "note": "❗ Nie mów <span class=\"line-through\">I don't go nowhere</span>. To podwójne przeczenie."
        },
        {
            "label": "Pytania",
            "color": "sky",
            "description": "W pytaniach najczęściej używamy <strong>anywhere</strong>. <strong>somewhere</strong> sugeruje, że mówca spodziewa się pozytywnej odpowiedzi albo ma konkretne miejsce na myśli.",
            "examples": [
                {
                    "en": "Do you want to go anywhere this weekend?",
                    "ua": "Czy chcesz gdzieś pojechać w ten weekend?"
                },
                {
                    "en": "Is there anywhere to eat near here?",
                    "ua": "Czy jest tu gdzieś w pobliżu coś do jedzenia?"
                }
            ],
            "note": "<span class=\"font-semibold\">Somewhere</span> w pytaniu brzmi bardziej konkretnie niż <span class=\"font-semibold\">anywhere</span>."
        }
    ]
}

{
    "title": "3. Anywhere vs nowhere",
    "intro": "Obie formy mogą wyrażać brak miejsca, ale budują zdanie inaczej:",
    "rows": [
        {
            "en": "I don't go anywhere on Sundays.",
            "ua": "W niedziele nigdzie nie wychodzę.",
            "note": "Przeczenie z <code class=\"font-mono text-xs\">don't</code> + <strong>anywhere</strong>."
        },
        {
            "en": "I go nowhere on Sundays.",
            "ua": "W niedziele nigdzie nie wychodzę.",
            "note": "Jednowyrazowe przeczenie z <strong>nowhere</strong>, bez dodatkowego <code class=\"font-mono text-xs\">not</code>."
        }
    ],
    "warning": "❗ Nie łącz <strong>nowhere</strong> z dodatkowym <code class=\"font-mono text-xs\">not</code>: <span class=\"line-through\">I don't go nowhere</span>."
}

{
    "title": "4. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Podwójne przeczenie z <strong>nowhere</strong>.",
            "wrong": "I don't go nowhere on Sundays.",
            "right": "✅ <span class=\"font-mono\">I don't go anywhere on Sundays.</span> / <span class=\"font-mono\">I go nowhere on Sundays.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie <strong>somewhere</strong> w neutralnym pytaniu.",
            "hint": "<span class=\"font-mono\">Do you want to go somewhere?</span> sugeruje, że masz na myśli jakieś konkretne miejsce. W pytaniu neutralnym częściej używamy <span class=\"font-mono\">anywhere</span>."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie <strong>everywhere</strong> z <strong>somewhere</strong>.",
            "hint": "<span class=\"font-mono\">I want to go somewhere in London.</span> oznacza „gdzieś w Londynie”. <span class=\"font-mono\">everywhere</span> znaczy „wszędzie”."
        }
    ]
}

{
    "title": "6. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwe słowo",
    "select_intro": "Wybierz <strong>somewhere / anywhere / nowhere / everywhere</strong>.",
    "selects": [
        {
            "label": "I can't find my keys ______. <span class=\"text-slate-500\">(nigdzie)</span>",
            "prompt": "Które słowo pasuje najlepiej?"
        },
        {
            "label": "She wants to live ______ near the sea. <span class=\"text-slate-500\">(gdzieś)</span>",
            "prompt": "Które słowo pasuje najlepiej?"
        },
        {
            "label": "Do you want to go ______ tonight? <span class=\"text-slate-500\">(gdzieś)</span>",
            "prompt": "Które słowo pasuje najlepiej?"
        }
    ],
    "options": [
        "somewhere",
        "anywhere",
        "nowhere",
        "everywhere"
    ],
    "input_title": "Ćwiczenie 2. Uzupełnij luki",
    "input_intro": "Wpisz <strong>somewhere / anywhere / nowhere / everywhere</strong>.",
    "inputs": [
        {
            "before": "I don't want to go ",
            "after": " tonight."
        },
        {
            "before": "You can buy good coffee ",
            "after": " in this city."
        },
        {
            "before": "She travels ",
            "after": " for work."
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Przepisz zdanie",
    "rephrase_intro": "Przepisz zdanie, używając <strong>anywhere</strong> albo <strong>nowhere</strong>.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I don't go anywhere on Saturdays.",
            "example_target": "I go nowhere on Saturdays."
        },
        {
            "original": "1. There isn't anywhere to sit.",
            "placeholder": "Przepisz z nowhere"
        },
        {
            "original": "2. He goes nowhere without his phone.",
            "placeholder": "Przepisz z not ... anywhere"
        }
    ]
}

